        // Cache is expired
        return null;
      }
      
      return parsedItem.data;
    } catch (error) {
      console.warn(`Failed to retrieve ${dataType} data from cache:`, error);
      return null;
    }
  }

  /**
   * Update cache metadata with the current timestamp and version
   */
