    try {
      const metadata = localStorage.getItem(CACHE_METADATA_KEY);
      
      if (!metadata) return null;
      
      return JSON.parse(metadata);
    } catch (error) {
      console.warn('Failed to get cache metadata:', error);
      return null;
    }
  }

